    solution_code: "queue<int> q; vector<int> topo; for(int i=0;i<n;i++)if(!indeg[i])q.push(i); while(!q.empty()){int u=q.front();q.pop();topo.push_back(u);for(auto&[v,w]:g[u])if(--indeg[v]==0)q.push(v);} vector<long long> dist(n,LLONG_MAX); dist[s]=0; for(int u:topo){if(dist[u]==LLONG_MAX)continue;for(auto&[v,w]:g[u])if(dist[u]+w<dist[v])dist[v]=dist[u]+w;} cout<<dist[t];",
