    solution_template: "#include <iostream>\n#include <vector>\n#include <queue>\n#include <climits>\nusing namespace std;\n\nint main() {\n  int n, m, src, dst, k; cin >> n >> m >> src >> dst >> k;\n  vector<vector<pair<int,int>>> g(n);\n  for(int i=0;i<m;i++){int u,v,w;cin>>u>>v>>w;g[u].push_back({v,w});}\n\n  // Bellman-Ford variant with k+1 iterations\n\n  return 0;\n}",
