    sheet: "Striver A2Z",
    solution_code: "for(int i=0;i<n;i++)for(int j=0;j<m;j++){if(i==0&&j==0)continue;int t=1e9;if(i>0)t=min(t,grid[i-1][j]);if(j>0)t=min(t,grid[i][j-1]);grid[i][j]+=t;}cout<<grid[n-1][m-1];",
