    sheet: "Striver A2Z",
    solution_code: "vector<vector<int>> sum(n,vector<int>(m)), cnt(n,vector<int>(m)); int dirs[4][2]={{1,0},{-1,0},{0,1},{0,-1}}; int total=0; for(int i=0;i<n;i++)for(int j=0;j<m;j++)if(grid[i][j]==1){total++;queue<pair<int,int>> q;q.push({i,j});vector<vector<int>> d(n,vector<int>(m,-1));d[i][j]=0;while(!q.empty()){auto[r,c]=q.front();q.pop();for(auto&[dr,dc]:dirs){int nr=r+dr,nc=c+dc;if(nr>=0&&nr<n&&nc>=0&&nc<m&&grid[nr][nc]!=2&&d[nr][nc]==-1){d[nr][nc]=d[r][c]+1;sum[nr][nc]+=d[nr][nc];cnt[nr][nc]++;q.push({nr,nc});}}}}int ans=1e9;for(int i=0;i<n;i++)for(int j=0;j<m;j++)if(grid[i][j]==0&&cnt[i][j]==total)ans=min(ans,sum[i][j]);cout<<(ans==1e9?-1:ans);",
