    solution_template: "#include <iostream>\n#include <vector>\n#include <queue>\n#include <climits>\nusing namespace std;\n\nint main() {\n  int n, m, k; cin >> n >> m >> k; k--;\n  vector<vector<pair<int,int>>> g(n);\n  for(int i=0;i<m;i++){int u,v,w;cin>>u>>v>>w;u--;v--;g[u].push_back({v,w});}\n\n  // Dijkstra, answer = max dist\n\n  return 0;\n}",
