    solution_template: "#include <iostream>\n#include <vector>\nusing namespace std;\n\nint main() {\n  int n; cin >> n;\n  vector<string> eqs(n);\n  for(int i=0;i<n;i++)cin>>eqs[i];\n\n  // DSU on 26 variables, process == first\n\n  return 0;\n}",
